INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (68, 'Eternal Sunshine of the Spotless Mind', 'https://image.tmdb.org/t/p/w500/5MwkWH9tYHv3mV9OdYTMR5qreIz.jpg', '2004-03-19',
                         'Joel Barish, heartbroken that his girlfriend underwent a procedure to erase him from her memory, decides to do the same. However, as he watches his memories of her fade away, he realises that he still loves her, and may be too late to correct his mistake.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (69, 'Zack Snyder''s Justice League', 'https://image.tmdb.org/t/p/w500/tnAuB8q5vv7Ax9UAEje5Xi4BXik.jpg', '2021-03-18',
                         'Determined to ensure Superman''s ultimate sacrifice was not in vain, Bruce Wayne aligns forces with Diana Prince with plans to recruit a team of metahumans to protect the world from an approaching threat of catastrophic proportions.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (70, 'Harry Potter and the Deathly Hallows: Part 2', 'https://image.tmdb.org/t/p/w500/c54HpQmuwXjHq2C9wmoACjxoom3.jpg', '2011-07-12',
