INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (71, 'Three Billboards Outside Ebbing, Missouri', 'https://image.tmdb.org/t/p/w500/bRYLt8fV82tdVoDppSFTZIcJiLN.jpg', '2017-12-01',
                         'After seven months have passed without a culprit in her daughter''s murder case, Mildred Hayes makes a bold move, painting three signs leading into her town with a controversial message directed at Bill Willoughby, the town''s revered chief of police. When his second-in-command Officer Jason Dixon, an immature mother''s boy with a penchant for violence, gets involved, the battle between Mildred and Ebbing''s law enforcement is only exacerbated.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (72, '2001: A Space Odyssey', 'https://image.tmdb.org/t/p/w500/ve72VxNqjGM69Uky4WTo2bK6rfq.jpg', '1968-04-02',
                         'Humanity finds a mysterious object buried beneath the lunar surface and sets off to find its origins with the help of HAL 9000, the world''s most advanced super computer.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (73, 'Hidden Figures', 'https://image.tmdb.org/t/p/w500/9lfz2W2uGjyow3am00rsPJ8iOyq.jpg', '2016-12-10',
