INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (74, 'The Avengers', 'https://image.tmdb.org/t/p/w500/RYMX2wcKCBAr24UyPD7xwmjaTn.jpg', '2012-04-25',
