INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (75, 'Oppenheimer', 'https://image.tmdb.org/t/p/w500/8Gxv8gSFCU0XGDykEGv7zR1n2ua.jpg', '2023-07-19',
