INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (76, 'The Grand Budapest Hotel', 'https://image.tmdb.org/t/p/w500/eWdyYQreja6JGCzqHWXpWHDrrPo.jpg', '2014-02-26',
