INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (77, 'The Wolf of Wall Street', 'https://image.tmdb.org/t/p/w500/kW9LmvYHAaS9iA0tHmZVq8hQYoq.jpg', '2013-12-25',
                         'A New York stockbroker refuses to cooperate in a large securities fraud case involving corruption on Wall Street, corporate banking world and mob infiltration. Based on Jordan Belfort''s autobiography.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (78, 'Requiem for a Dream', 'https://image.tmdb.org/t/p/w500/9BTwsLaMVHOGFlmsSlx5QYCaXb.jpg', '2000-10-06',
