INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (79, 'Harry Potter and the Prisoner of Azkaban', 'https://image.tmdb.org/t/p/w500/aWxwnYoe8p2d2fcxOqtvAtJ72Rw.jpg', '2004-05-31',
