INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (80, 'American Beauty', 'https://image.tmdb.org/t/p/w500/wby9315QzVKdW9BonAefg8jGTTb.jpg', '1999-09-15',
