INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (81, 'Obsession', 'https://image.tmdb.org/t/p/w500/6X4qFYBsG3bpWDG2XIKqr04kFJa.jpg', '2026-05-13',
