INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (82, 'Lee Cronin''s The Mummy', 'https://image.tmdb.org/t/p/w500/1q308iixueCU4pFtSYugNOevtNx.jpg', '2026-04-15',
