INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (83, 'Kara', 'https://image.tmdb.org/t/p/w500/uIrFdMWlJFdc1jPBP9bxeaISCDj.jpg', '2026-04-30',
