INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (84, 'Tom Clancy''s Jack Ryan: Ghost War', 'https://image.tmdb.org/t/p/w500/8ehYxUh5MWE41AeE9gkHE8DKzvB.jpg', '2026-05-20',
