INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (85, 'The Punisher: One Last Kill', 'https://image.tmdb.org/t/p/w500/qQclTgLMDvGBuUBFGHRipxkEwWR.jpg', '2026-05-12',
