INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (86, 'Backrooms', 'https://image.tmdb.org/t/p/w500/rhGx6E3qRNMgj3i5su2oukNHwIQ.jpg', '2026-05-27',
                         'A strange doorway appears in the basement of a furniture showroom.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
