INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (88, 'The Super Mario Galaxy Movie', 'https://image.tmdb.org/t/p/w500/eJGWx219ZcEMVQJhAgMiqo8tYY.jpg', '2026-04-01',
