INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (89, 'The Matrix', 'https://image.tmdb.org/t/p/w500/aOIuZAjPaRIE6CMzbazvcHuHXDc.jpg', '1999-03-31',
