INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (90, 'Dhurandhar: The Revenge', 'https://image.tmdb.org/t/p/w500/ov8vrRLZGoXHpYjSY9Vpv1tHJX7.jpg', '2026-03-18',
