INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (91, 'Swapped', 'https://image.tmdb.org/t/p/w500/tHhxWxge06goXU6ZQH1hj7vK8Hd.jpg', '2026-05-01',
