INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (92, 'Your Heart Will Be Broken', 'https://image.tmdb.org/t/p/w500/7wIBfBl2gejt6xHxNSK0reVIm7E.jpg', '2026-03-26',
                         'High school student Polina is saved from bullying at her new school and makes a deal with the main bully Bars: he must pretend to be her boyfriend and protect her, and she must do everything he says. During this game, the couple develops real feelings, but her family and classmates have reasons to separate the lovers.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (93, 'Door II: Tokyo Diary', 'https://image.tmdb.org/t/p/w500/lskJ34j4VKwbMwcvFSQeNYEdt8g.jpg', '1991-04-25',
                         'Ai is a call girl that makes good money for what she does but there’s always at risk no matter how good the money is.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (94, 'Kattalan', 'https://image.tmdb.org/t/p/w500/53FATyQirV8BuBcrsQMGPvGKgCu.jpg', '2026-05-14',
                         'Power-hungry forces clash in the Ivory cartel war-a fierce story of control, vengeance, and survival where compassion vanishes and only the ruthless endure.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (95, 'Chand Mera Dil', 'https://image.tmdb.org/t/p/w500/9LPkXJustudEBgPZEm9tgDx5KtC.jpg', '2026-05-22',
                         'Aarav and Chandni''s passionate college romance is struck by adulthood far too soon, forcing the two young lovers to balance their ambitions with responsibility and realize the evolved meaning of love.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (96, 'Mortal Kombat II', 'https://image.tmdb.org/t/p/w500/lIsMeDbwntNXSUVHmWMMRXEZOVc.jpg', '2026-05-06',
                         'The fan favorite champions—now joined by Johnny Cage himself—are pitted against one another in the ultimate, no-holds barred, gory battle to defeat the dark rule of Shao Kahn that threatens the very existence of the Earthrealm and its defenders.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (97, 'The Shadow''s Edge', 'https://image.tmdb.org/t/p/w500/cHKo3m8N1fwvEy2ZEr0xGmmMODV.jpg', '2025-08-16',
                         'Macau Police brings the tracking expert police officer out of retirement to help catch a dangerous group of professional thieves.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (98, 'Avatar: Fire and Ash', 'https://image.tmdb.org/t/p/w500/aabwWZWx6z1aYP4PX2ADvbDKktd.jpg', '2025-12-17',
                         'In the wake of the devastating war against the RDA and the loss of their eldest son, Jake Sully and Neytiri face a new threat on Pandora: the Ash People, a violent and power-hungry Na''vi tribe led by the ruthless Varang. Jake''s family must fight for their survival and the future of Pandora in a conflict that pushes them to their emotional and physical limits.');
INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (99, 'Iron Lung', 'https://image.tmdb.org/t/p/w500/sIwakdbMGS1krtgendTWpxTY9Hw.jpg', '2026-01-30',
