INSERT INTO movie (id, title, poster_url, release_date, overview)
                 VALUES (100, 'Graphic Desires', 'https://image.tmdb.org/t/p/w500/3BjLdTWRiHc1ISIZMFvToOmghOM.jpg', '2023-08-31',
                         'When reclusive Franklin cheats on his partner with a mysterious girl he meets on a dating app, it becomes the start of a deadly obsession.');